import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Severity {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Vulnerability {
  type: string;
  severity: Severity;
  description: string;
  fixSuggestion: string;
  lineRange?: string;
}

export interface ScanResult {
  id: string;
  timestamp: string;
  vulnerabilities: Vulnerability[];
  overallRiskScore: number;
  summary: string;
  fileName: string;
}

export interface Dependency {
  name: string;
  version: string;
  status: 'secure' | 'vulnerable';
  latestVersion: string;
  cve?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ScanResult, Severity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCodeSecurity = async (code: string, fileName: string): Promise<ScanResult> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Perform a deep security audit on the following code snippet for file "${fileName}". Identify vulnerabilities like OWASP Top 10, logic flaws, or hardcoded secrets.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallRiskScore: { type: Type.INTEGER, description: "Risk score from 0-100" },
            summary: { type: Type.STRING, description: "Overall security summary" },
            vulnerabilities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ["Low", "Medium", "High", "Critical"] },
                  description: { type: Type.STRING },
                  fixSuggestion: { type: Type.STRING },
                  lineRange: { type: Type.STRING }
                },
                required: ["type", "severity", "description", "fixSuggestion"]
              }
            }
          },
          required: ["overallRiskScore", "summary", "vulnerabilities"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      fileName,
      ...data
    };
  } catch (error) {
    console.error("AI Scan failed:", error);
    throw new Error("Failed to complete security scan. Please check your API key.");
  }
};

