import React from 'react';
import { Severity } from '../types';

const RiskBadge: React.FC<{ severity: Severity }> = ({ severity }) => {
  const colors = {
    [Severity.LOW]: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
