import React, { useState } from 'react';
import { analyzeCodeSecurity } from '../services/geminiService';
import { ScanResult, Severity } from '../types';
import RiskBadge from './RiskBadge';

const DEFAULT_CODE = `import sqlite3

def get_user_data(username):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    # Vulnerable to SQL Injection
    query = "SELECT * FROM users WHERE username = '" + username + "'"
    cursor.execute(query)
    return cursor.fetchone()

API_KEY = "AKIA1234567890EXAMPLE" # Hardcoded credential`;

const Scanner: React.FC<{ onResult: (res: ScanResult) => void }> = ({ onResult }) => {
  const [code, setCode] = useState(DEFAULT_CODE);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<ScanResult | null>(null);

  const handleScan = async () => {
    setIsScanning(true);
    try {
      const scan = await analyzeCodeSecurity(code, "example_script.py");
      setResult(scan);
      onResult(scan);
    } catch (err) {
      alert(err instanceof Error ? err.message : "An unexpected error occurred");
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">Code Vulnerability Scanner</h2>
          <p className="text-slate-400">Static analysis & AI reasoning powered by Gemini-3 Flash</p>
        </div>
        <button
          onClick={handleScan}
          disabled={isScanning || !code.trim()}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-lg font-bold transition-all ${
            isScanning
              ? 'bg-slate-700 text-slate-400 cursor-not-allowed'
              : 'bg-emerald-500 hover:bg-emerald-600 text-slate-900 shadow-lg shadow-emerald-500/20'
          }`}
        >
          {isScanning ? (
            <><i className="fa-solid fa-spinner animate-spin"></i> Analyzing...</>
          ) : (
            <><i className="fa-solid fa-bolt-lightning"></i> Run Security Scan</>
          )}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-slate-800 rounded-xl border border-slate-700 flex flex-col shadow-xl">
          <div className="px-4 py-2 border-b border-slate-700 flex items-center justify-between">
            <span className="text-sm font-medium text-slate-400">Source Editor</span>
            <div className="flex gap-2">
              <div className="w-3 h-3 rounded-full bg-red-500/20"></div>
              <div className="w-3 h-3 rounded-full bg-yellow-500/20"></div>
              <div className="w-3 h-3 rounded-full bg-green-500/20"></div>
            </div>
          </div>
          <textarea
            value={code}
            onChange={(e) => setCode(e.target.value)}
            className="flex-1 min-h-[400px] p-6 bg-slate-900/50 text-slate-300 mono text-sm focus:outline-none resize-none rounded-b-xl"
            placeholder="Paste your code here..."
          />
        </div>

        <div className="bg-slate-800 rounded-xl border border-slate-700 flex flex-col overflow-hidden shadow-xl">
          <div className="px-4 py-2 border-b border-slate-700 bg-slate-800/50">
            <span className="text-sm font-medium text-slate-400">Scan Results</span>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-4 max-h-[400px]">
            {!result && !isScanning && (
              <div className="h-full flex flex-col items-center justify-center text-slate-500 py-20">
                <i className="fa-solid fa-magnifying-glass-shield text-5xl mb-4 opacity-20"></i>
                <p>Waiting for scan results...</p>
              </div>
            )}

            {isScanning && (
              <div className="space-y-4">
                {[1, 2, 3].map(i => (
                  <div key={i} className="animate-pulse flex gap-4">
                    <div className="w-1 bg-slate-700 rounded-full h-20"></div>
                    <div className="flex-1 space-y-2">
                      <div className="h-4 bg-slate-700 rounded w-1/4"></div>
                      <div className="h-4 bg-slate-700 rounded w-3/4"></div>
                      <div className="h-4 bg-slate-700 rounded w-1/2"></div>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {result && !isScanning && (
              <>
                <div className="p-4 bg-slate-900/80 rounded-lg border border-slate-700 mb-6">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-xs uppercase font-bold text-slate-500">Security Summary</span>
                    <span className={`text-xl font-bold ${result.overallRiskScore > 70 ? 'text-red-400' : 'text-emerald-400'}`}>
                      Score: {result.overallRiskScore}/100
                    </span>
                  </div>
                  <p className="text-sm text-slate-300 leading-relaxed">{result.summary}</p>
                </div>

                <div className="space-y-4">
                  <h4 className="text-xs uppercase font-bold text-slate-500">Detected Issues ({result.vulnerabilities.length})</h4>
                  {result.vulnerabilities.map((vuln, idx) => (
                    <div key={idx} className="p-4 bg-slate-900 rounded-lg border-l-4 border-l-emerald-500 border border-slate-700 hover:border-slate-600 transition-colors">
                      <div className="flex justify-between items-start mb-2">
                        <h5 className="font-semibold text-slate-200">{vuln.type}</h5>
                        <RiskBadge severity={vuln.severity} />
                      </div>
                      <p className="text-sm text-slate-400 mb-3">{vuln.description}</p>
                      <div className="bg-emerald-500/5 p-3 rounded border border-emerald-500/10">
                        <p className="text-xs font-bold text-emerald-400 uppercase mb-1 flex items-center gap-1">
                          <i className="fa-solid fa-lightbulb"></i> AI Recommendation
                        </p>
                        <p className="text-xs text-slate-300 mono">{vuln.fixSuggestion}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Scanner;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Scanner from './components/Scanner';
import DashboardOverview from './components/DashboardOverview';
import DependencyScan from './components/DependencyScan';
import { ScanResult } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('overview');
  const [scanHistory, setScanHistory] = useState<ScanResult[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Load history from localStorage if available
  useEffect(() => {
    const saved = localStorage.getItem('secureops_history');
    if (saved) {
      try {
        setScanHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  const handleNewScanResult = (result: ScanResult) => {
    const updated = [result, ...scanHistory].slice(0, 50); // Keep last 50
    setScanHistory(updated);
    localStorage.setItem('secureops_history', JSON.stringify(updated));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'overview':
        return <DashboardOverview history={scanHistory} />;
      case 'scan':
        return <Scanner onResult={handleNewScanResult} />;
      case 'dependencies':
        return <DependencyScan />;
      case 'history':
        return (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">Historical Analysis</h2>
            <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-xl overflow-hidden">
               {scanHistory.length > 0 ? (
                 <table className="w-full text-left">
                   <thead className="bg-slate-900/50 border-b border-slate-700">
                     <tr>
                       <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">File Name</th>
                       <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Risk Score</th>
                       <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Issues</th>
                       <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Timestamp</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-700">
                     {scanHistory.map((scan) => (
                       <tr key={scan.id} className="hover:bg-slate-700/30 cursor-pointer" onClick={() => setActiveTab('scan')}>
                         <td className="px-6 py-4 text-slate-200 font-medium">{scan.fileName}</td>
                         <td className="px-6 py-4">
                            <span className={`font-bold ${scan.overallRiskScore > 70 ? 'text-red-400' : 'text-emerald-400'}`}>
                              {scan.overallRiskScore}%
                            </span>
                         </td>
                         <td className="px-6 py-4 text-slate-400">{scan.vulnerabilities.length}</td>
                         <td className="px-6 py-4 text-slate-500 text-sm">
                           {new Date(scan.timestamp).toLocaleString()}
                         </td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               ) : (
                 <div className="p-20 text-center text-slate-500">
                   <i className="fa-solid fa-box-archive text-5xl mb-4 opacity-20"></i>
                   <p>No historical scan data found</p>
                 </div>
               )}
            </div>
          </div>
        );
      default:
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-slate-500">
            <i className="fa-solid fa-wrench text-6xl mb-6 opacity-20"></i>
            <h3 className="text-xl font-bold text-slate-400">Feature Under Development</h3>
            <p>This module is planned for Stage 2 (Core Development).</p>
          </div>
        );
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-950 text-slate-200">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 overflow-y-auto">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-8 bg-slate-900/50 sticky top-0 z-10 backdrop-blur-md">
          <div className="flex items-center gap-4">
             <h1 className="text-sm font-semibold text-slate-400 uppercase tracking-widest">
               SecureOpsAI / {activeTab}
             </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 px-3 py-1 bg-emerald-500/10 text-emerald-400 rounded-full text-xs font-bold border border-emerald-500/20">
              <i className="fa-solid fa-check-double"></i>
              CI/CD SIMULATED
            </div>
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center border border-slate-600">
              <i className="fa-solid fa-user text-xs"></i>
            </div>
          </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Chat } from "@google/genai";
import { ScanResult, Severity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCodeSecurity = async (code: string, fileName: string, policies: string[] = ['OWASP']): Promise<ScanResult> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Perform a deep security audit on this code: "${fileName}". 
      Policies to enforce: ${policies.join(', ')}.

      For each vulnerability, provide:
      1. A detailed description.
      2. A specific code-fix snippet.
      3. A risk score (0-100).

      Code:
      ${code}`,
      config: {
        thinkingConfig: { thinkingBudget: 2000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallRiskScore: { type: Type.INTEGER },
            summary: { type: Type.STRING },
            vulnerabilities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ["Low", "Medium", "High", "Critical"] },
                  description: { type: Type.STRING },
                  fixSuggestion: { type: Type.STRING },
                  remediationCode: { type: Type.STRING, description: "The corrected code snippet" }
                },
                required: ["type", "severity", "description", "fixSuggestion", "remediationCode"]
              }
            }
          },
          required: ["overallRiskScore", "summary", "vulnerabilities"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      fileName,
      ...data
    };
  } catch (error) {
    console.error("AI Scan failed:", error);
    throw new Error("Security Engine failure. Ensure your API key is valid.");
  }
};

export const createSecurityChat = (): Chat => {
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: 'You are an expert DevSecOps Agent named SecureOpsBot. You help developers fix vulnerabilities found in their code scans. Be concise, technical, and prioritize security best practices.',
    },
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { createSecurityChat } from '../services/geminiService';

const ChatPanel: React.FC = () => {
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatRef.current = createSecurityChat();
    setMessages([{ role: 'bot', text: 'Hello! I am your SecureOps Assistant. Ask me anything about your scan results or security best practices.' }]);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const response = await chatRef.current.sendMessage({ message: userMsg });
      setMessages(prev => [...prev, { role: 'bot', text: response.text }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'bot', text: 'Error connecting to security brain. Please try again.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 w-96 h-[500px] bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl flex flex-col z-50 overflow-hidden">
      <div className="p-4 bg-slate-800 border-b border-slate-700 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
          <span className="font-bold text-sm">Security Assistant</span>
        </div>
        <i className="fa-solid fa-robot text-slate-500"></i>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-xl text-sm ${
              m.role === 'user' ? 'bg-emerald-600 text-white rounded-br-none' : 'bg-slate-800 text-slate-300 rounded-bl-none border border-slate-700'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-800 p-3 rounded-xl rounded-bl-none border border-slate-700">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-slate-700 bg-slate-900/50">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about a vulnerability..."
            className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2 pl-4 pr-10 text-sm focus:outline-none focus:border-emerald-500 transition-colors"
          />
          <button 
            onClick={handleSend}
            className="absolute right-2 top-1.5 text-emerald-500 hover:text-emerald-400"
          >
            <i className="fa-solid fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatPanel;

import React, { useState } from 'react';

const Settings: React.FC = () => {
  const [policies, setPolicies] = useState({
    owasp: true,
    sans25: false,
    pci: false,
    hipaa: false,
    secrets: true,
  });

  const togglePolicy = (key: keyof typeof policies) => {
    setPolicies(prev => ({ ...prev, [key]: !prev[key] }));
  };

  return (
    <div className="max-w-3xl space-y-8">
      <div>
        <h2 className="text-2xl font-bold">Security Engine Settings</h2>
        <p className="text-slate-400">Configure the AI scanning logic and compliance requirements.</p>
      </div>

      <div className="bg-slate-800 rounded-xl border border-slate-700 divide-y divide-slate-700 shadow-xl overflow-hidden">
        {[
          { id: 'owasp', label: 'OWASP Top 10 (2024)', desc: 'Standard awareness document for developers and web application security.' },
          { id: 'sans25', label: 'SANS Top 25', desc: 'Widespread and critical errors that can lead to serious vulnerabilities.' },
          { id: 'pci', label: 'PCI-DSS Compliance', desc: 'Security standards for organizations that handle branded credit cards.' },
          { id: 'secrets', label: 'Secret Detection', desc: 'Automatically identify hardcoded API keys, tokens, and credentials.' },
        ].map((item) => (
          <div key={item.id} className="p-6 flex items-center justify-between hover:bg-slate-700/20 transition-colors">
            <div className="space-y-1">
              <p className="font-bold text-slate-200">{item.label}</p>
              <p className="text-sm text-slate-500">{item.desc}</p>
            </div>
            <button
              onClick={() => togglePolicy(item.id as any)}
