}

import { GoogleGenAI, Type, Chat } from "@google/genai";
import { ScanResult, Severity, Dependency } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCodeSecurity = async (code: string, fileName: string, policies: string[] = ['OWASP']): Promise<ScanResult> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Perform a deep security audit on this code: "${fileName}". 
      Policies: ${policies.join(', ')}.

      Output specific vulnerabilities and high-quality remediation code.

      Code:
      ${code}`,
      config: {
        thinkingConfig: { thinkingBudget: 4000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallRiskScore: { type: Type.INTEGER },
            summary: { type: Type.STRING },
            vulnerabilities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  severity: { type: Type.STRING, enum: ["Low", "Medium", "High", "Critical"] },
                  description: { type: Type.STRING },
                  fixSuggestion: { type: Type.STRING },
                  remediationCode: { type: Type.STRING }
                },
                required: ["type", "severity", "description", "fixSuggestion", "remediationCode"]
              }
            }
          },
          required: ["overallRiskScore", "summary", "vulnerabilities"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      fileName,
      ...data
    };
  } catch (error) {
    console.error("AI Scan failed:", error);
    throw new Error("Security Engine failure.");
  }
};

export const analyzeDependencies = async (manifestContent: string): Promise<Dependency[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze these dependencies for security risks, transitive vulnerabilities, or license issues:

      ${manifestContent}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              version: { type: Type.STRING },
              status: { type: Type.STRING, enum: ["secure", "vulnerable", "warning"] },
              latestVersion: { type: Type.STRING },
              riskReason: { type: Type.STRING },
              cve: { type: Type.STRING }
            },
            required: ["name", "version", "status", "latestVersion"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (e) {
    return [];
  }
};

